LIMIT 1
OFFSET 4

SELECT ?player ?currentTeam ?currentTeamLabel WHERE {
  ?team wdt:P31 wd:Q175225;
        rdfs:label "Syracuse Orange men's soccer" (lang:en).
  ?player wdt:P19 wd:Q34739;
          wdt:P10006 ?team;
          p:P10006 ?statement.
  ?statement pq:P582 ?endYear.
  FILTER (year(?endYear) = 2019).
  ?player wdt:P10006 ?currentTeam.
  ?currentTeam rdfs:label ?currentTeamLabel (lang:en).
}

SELECT DISTINCT ?altName WHERE {
  ?city wdt:P17 wd:Q13 ; wdt:P31 wd:Q515 ; wdt:P1344 "9th" .
  ?site wdt:P131 ?city ; wdt:P31 wd:Q37255 ; wdt:P1559 ?altName .
}

SELECT ?year WHERE {
  ?race wdt:P449 wd:Q16985525 ; wdt:P31 wd:Q26095 ; wdt:P1132 "Nulla è più sacra della fede vera unita alle altre virtù" @it ; wdt:P585 ?year .
}

SELECT ?person WHERE {
  ?person wdt:P1343 wd:Q143451 ; wdt:P108 ?organization .
  ?organization wdt:P1543 ?goal .
  FILTER(regex(?goal , 'moral' , 'i') && regex(?goal , 'ethical' , 'i') && regex(?goal , 'young' , 'i') && regex(?goal , 'prepare' , 'i'))
}

SELECT ?game WHERE {
  wd:Q123456 wdt:P577 ?releaseDate .
  FILTER(YEAR(?releaseDate) = 1996)
}

SELECT(YEAR(?birthDate) AS ?birthYear) WHERE {
  ?player wdt:P106 wd:Q14230 ; wdt:P1372 wd:Q26523028 ; p:P1550 ?draftStatement .
  ?draftStatement ps:P1550 wd:Q223783 ; pq:P585 ?draftDate .
  ?player wdt:P569 ?birthDate .
  FILTER(YEAR(?draftDate) = 2019)
}

SELECT ?team WHERE {
  {
    wd:Q23655322 wdt:P527 ?team .
  } UNION {
    wd:Q29554835 wdt:P527 ?team .
  }
}

SELECT ?team ?foundationYear ?promotionYear WHERE {
  ?team wdt:P3005 wd:Q4209853 ; wdt:P1594 ?venue ; wdt:P571 ?foundationYear ; wdt:P1052 ?promotionYear .
  ?venue wdt:P1182 ?capacity .
  ?capacity wikibase:quantityAmount ?number .
  FILTER(?number = 3280)
}
